import os
import hashlib
import secrets
from datetime import datetime, timedelta
from functools import wraps

from flask import Flask, request, redirect, url_for, session, render_template_string, flash, g

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))
app.permanent_session_lifetime = timedelta(days=7)

# Simple in-memory user store (replace with database in production)
users_db = {}
# Simple in-memory session store
sessions_db = {}


def hash_password(password, salt=None):
    """Hash a password with a salt."""
    if salt is None:
        salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt.encode('utf-8'), 100000)
    return salt, hashed.hex()


def verify_password(password, salt, hashed):
    """Verify a password against its hash."""
    _, new_hash = hash_password(password, salt)
    return new_hash == hashed


def create_session(user_id, remember=False):
    """Create a new session for a user."""
    session_token = secrets.token_hex(32)
    expiry = datetime.utcnow() + timedelta(days=30 if remember else 1)
    sessions_db[session_token] = {
        'user_id': user_id,
        'created_at': datetime.utcnow(),
        'expires_at': expiry,
        'remember': remember,
        'ip_address': request.remote_addr,
        'user_agent': request.headers.get('User-Agent', ''),
    }
    return session_token


def get_session(session_token):
    """Retrieve and validate a session."""
    if session_token not in sessions_db:
        return None
    sess = sessions_db[session_token]
    if datetime.utcnow() > sess['expires_at']:
        # Session expired, clean it up
        del sessions_db[session_token]
        return None
    return sess


def destroy_session(session_token):
    """Destroy a session."""
    if session_token in sessions_db:
        del sessions_db[session_token]


def destroy_all_user_sessions(user_id):
    """Destroy all sessions for a given user."""
    tokens_to_remove = [
        token for token, sess in sessions_db.items()
        if sess['user_id'] == user_id
    ]
    for token in tokens_to_remove:
        del sessions_db[token]


def login_required(f):
    """Decorator to require login for a view."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if g.get('current_user') is None:
            flash('Please log in to access this page.', 'warning')
            return redirect(url_for('login', next=request.url))
        return f(*args, **kwargs)
    return decorated_function


@app.before_request
def load_user_from_session():
    """Load the current user before each request."""
    g.current_user = None
    session_token = session.get('session_token')
    if session_token:
        sess = get_session(session_token)
        if sess:
            user_id = sess['user_id']
            if user_id in users_db:
                g.current_user = {
                    'id': user_id,
                    'username': users_db[user_id]['username'],
                }
                # Extend session if "remember me" was checked
                if sess['remember']:
                    sess['expires_at'] = datetime.utcnow() + timedelta(days=30)
            else:
                # User no longer exists
                destroy_session(session_token)
                session.pop('session_token', None)
        else:
            # Invalid or expired session
            session.pop('session_token', None)


