@app.route('/register', methods=['GET', 'POST'])
def register():
    if g.current_user:
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        confirm_password = request.form.get('confirm_password', '')

        # Validation
        if not username or not password:
            flash('Username and password are required.', 'error')
            return render_template_string(BASE_TEMPLATE, title='Register', content=REGISTER_FORM, g=g)

        if len(username) < 3:
            flash('Username must be at least 3 characters long.', 'error')
            return render_template_string(BASE_TEMPLATE, title='Register', content=REGISTER_FORM, g=g)

        if len(password) < 6:
            flash('Password must be at least 6 characters long.', 'error')
            return render_template_string(BASE_TEMPLATE, title='Register', content=REGISTER_FORM, g=g)

        if password != confirm_password:
            flash('Passwords do not match.', 'error')
            return render_template_string(BASE_TEMPLATE, title='Register', content=REGISTER_FORM, g=g)

        # Check if username already exists
        for uid, user in users_db.items():
            if user['username'].lower() == username.lower():
                flash('Username already taken.', 'error')
                return render_template_string(BASE_TEMPLATE, title='Register', content=REGISTER_FORM, g=g)

        # Create user
        user_id = secrets.token_hex(16)
        salt, hashed = hash_password(password)
        users_db[user_id] = {
            'username': username,
            'password_salt': salt,
            'password_hash': hashed,
            'created_at': datetime.utcnow(),
        }

        flash('Registration successful! Please log in.', 'success')
        return redirect(url_for('login'))

    return render_template_string(BASE_TEMPLATE, title='Register', content=REGISTER_FORM, g=g)


@app.route('/login', methods=['GET', 'POST'])
def login():
    if g.current_user:
        return redirect(url_for('dashboard'))

    if request.method == 'POST':
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')
        remember = request.form.get('remember') == 'on'

        # Find user
        found_user_id = None
        found_user = None
        for uid, user in users_db.items():
            if user['username'].lower() == username.lower():
                found_user_id = uid
                found_user = user
                break

        if found_user and verify_password(password, found_user['password_salt'], found_user['password_hash']):
            # Create session
            session_token = create_session(found_user_id, remember=remember)
            session['session_token'] = session_token

            if remember:
                session.permanent = True
            else:
                session.permanent = False

            flash('Login successful!', 'success')

            # Redirect to next page if specified
            next_page = request.args.get('next')
            if next_page:
                return redirect(next_page)
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password.', 'error')

    return render_template_string(BASE_TEMPLATE, title='Login', content=LOGIN_FORM, g=g)


@app.route('/logout')
def logout():
    session_token = session.get('session_token')
    if session_token:
        destroy_session(session_token)
    session.clear()
    flash('You have been logged out.', 'info')
    return redirect(url_for('index'))


