@app.route('/sessions')
@login_required
def active_sessions():
    user_id = g.current_user['id']
    current_token = session.get('session_token')

    session_list = []
    for token, sess in sessions_db.items():
        if sess['user_id'] == user_id:
            is_current = token == current_token
            session_list.append({
                'token': token,
                'created_at': sess['created_at'],
                'expires_at': sess['expires_at'],
                'ip_address': sess['ip_address'],
                'user_agent': sess['user_agent'][:80],
                'remember': sess['remember'],
                'is_current': is_current,
            })

    # Sort by creation date, newest first
    session_list.sort(key=lambda x: x['created_at'], reverse=True)

    items_html = ''
    for s in session_list:
        css_class = 'session-item current' if s['is_current'] else 'session-item'
        current_label = ' <strong>(Current Session)</strong>' if s['is_current'] else ''
        items_html += """
        <div class="{css_class}">
            <p>{current_label}</p>
            <p><strong>Created:</strong> {created}</p>
            <p><strong>Expires:</strong> {expires}</p>
            <p><strong>IP:</strong> {ip}</p>
            <p><strong>Browser:</strong> {ua}</p>
            <p><strong>Remember me:</strong> {remember}</p>
            {revoke_btn}
        </div>
        """.format(
            css_class=css_class,
            current_label=current_label,
            created=s['created_at'].strftime('%Y-%m-%d %H:%M:%S UTC'),
            expires=s['expires_at'].strftime('%Y-%m-%d %H:%M:%S UTC'),
            ip=s['ip_address'],
            ua=s['user_agent'],
            remember='Yes' if s['remember'] else 'No',
            revoke_btn='' if s['is_current'] else
                '<form method="POST" action="%s" style="display:inline;"><button class="btn-danger" type="submit">Revoke</button></form>' %
                url_for('revoke_session', token=s['token']),
        )

    content = """
    <p>These are your currently active sessions:</p>
    {items}
    <br>
    <form method="POST" action="{logout_all_url}">
        <button class="btn-danger" type="submit">Logout All Other Sessions</button>
    </form>
    """.format(
        items=items_html if items_html else '<p>No active sessions found.</p>',
        logout_all_url=url_for('logout_all_others'),
    )

    return render_template_string(BASE_TEMPLATE, title='Active Sessions', content=content, g=g)


@app.route('/sessions/revoke/<token>', methods=['POST'])
@login_required
def revoke_session(token):
    user_id = g.current_user['id']
    sess = sessions_db.get(token)
    if sess and sess['user_id'] == user_id:
        destroy_session(token)
        flash('Session revoked successfully.', 'success')
    else:
        flash('Session not found.', 'error')
    return redirect(url_for('active_sessions'))


@app.route('/sessions/logout-others', methods=['POST'])
@login_required
def logout_all_others():
    user_id = g.current_user['id']
    current_token = session.get('session_token')

    tokens_to_remove = [
        token for token, sess in sessions_db.items()
        if sess['user_id'] == user_id and token != current_token
    ]
    for token in tokens_to_remove:
        del sessions_db[token]

    flash('All other sessions have been logged out.', 'success')
    return redirect(url_for('active_sessions'))


@app.route('/change-password', methods=['GET', 'POST'])
@login_required
def change_password():
    if request.method == 'POST':
        current_password = request.form.get('current_password', '')
        new_password = request.form.get('new_password', '')
        confirm_password = request.form.get('confirm_password', '')

        user_id = g.current_user['id']
        user = users_db[user_id]

        if not verify_password(current_password, user['password_salt'], user['password_hash']):
            flash('Current password is incorrect.', 'error')
        elif len(new_password) < 6:
            flash('New password must be at least 6 characters long.', 'error')
        elif new_password != confirm_password:
            flash('New passwords do not match.', 'error')
        else:
            salt, hashed = hash_password(new_password)
            users_db[user_id]['password_salt'] = salt
            users_db[user_id]['password_hash'] = hashed

            # Invalidate all other sessions for security
            current_token = session.get('session_token')
            tokens_to_remove = [
                token for token, sess in sessions_db.items()
                if sess['user_id'] == user_id and token != current_token
            ]
            for token in tokens_to_remove:
                del sessions_db[token]

            flash('Password changed successfully. All other sessions have been logged out.', 'success')
            return redirect(url_for('dashboard'))

    content = """
    <form method="POST">
        <label for="current_password">Current Password:</label>
        <input type="password" id="current_password" name="current_password" required>
        <label for="new_password">New Password:</label>
        <input type="password" id="new_password" name="new_password" required>
        <label for="confirm_password">Confirm New Password:</label>
        <input type="password" id="confirm_password" name="confirm_password" required>
        <button type="submit">Change Password</button>
    </form>
    """
    return render_template_string(BASE_TEMPLATE, title='Change Password', content=content, g=g)


# Periodic cleanup of expired sessions (runs before each request)
@app.before_request
def cleanup_expired_sessions():
    """Remove expired sessions periodically."""
    now = datetime.utcnow()
    expired = [token for token, sess in sessions_db.items() if now > sess['expires_at']]
    for token in expired:
        del sessions_db[token]


